from(bucket: "dali_devices")
  |> range(start: -7d)
  |> filter(fn: (r) => r["_measurement"] == "dali_property" and r.title == v.joce_device_title)
  |> group(columns: ["device_guid", "title", "property"])
  |> filter(fn: (r) => r["property"] == "driverOperationTime")
  |> aggregateWindow(every: v.windowPeriod, fn: mean, createEmpty: false)
  |> keep(columns: ["device_guid", "title", "property", "_value", "unit", "_time"])
  |> last()
  |> map(fn: (r) => {
    // Convert float _value to integer seconds
    seconds = int(v: r._value)

    // Define constants
    secondsPerYear = 365 * 24 * 3600   // 31,536,000
    secondsPerDay  = 24 * 3600         // 86,400
    secondsPerHour = 3600
    secondsPerMin  = 60

    // Calculate components
    years  = seconds / secondsPerYear
    days   = (seconds % secondsPerYear) / secondsPerDay
    hours  = (seconds % secondsPerDay) / secondsPerHour
    minutes = (seconds % secondsPerHour) / secondsPerMin
    remainingSeconds = seconds % secondsPerMin

    // Build list of non-zero parts — do NOT reassign, build once
    parts = [
      if years > 0 then "${years}y " else "",
      if days > 0 then "${days}d " else "",
      if hours > 0 then "${hours}h " else "",
      if minutes > 0 then "${minutes}m " else "",
      if remainingSeconds > 0 then "${remainingSeconds}s" else ""
    ]

    // Join non-empty parts with space
    formatted = parts[0] + parts[1] + parts[3]  + parts[4]

    // Return updated record — use `r with` to override _value and unit
    return {
      r with
      _value: if formatted == "" then "0s" else formatted,
      unit: "duration"
    }
  })

