from(bucket: "dali_devices")
  |> range(start: -7d)
  |> filter(fn: (r) => r["_measurement"] == "dali_property" and r.title == v.joce_device_title and r.title!="Unknown")
  |> group(columns: ["device_guid", "title", "property"])
  |> filter(fn: (r) => r["property"] == "driverEnergyConsumption")
  |> keep(columns: ["device_guid", "title", "property", "_value", "unit", "_time"])
  |> last()
  |> map(fn: (r) => {
    // Convert integer _value to float, then divide by 1000
    energy_kWh = float(v: r._value) / 1000.0
    return {
      r with
      _value: energy_kWh,
      unit: "kWh"  // 👈 More accurate unit than "duration"
    }
  })
